import type { FC, PropsWithChildren } from 'react';
import React from 'react';
import { Button, Input } from '../..';
import './partial-lm.less';

const Container: FC<PropsWithChildren<{ theme: 'light' | 'dark' }>> = ({ children, theme }) => (
  <div className={`${theme}-container`}>
    <Button type="primary">{`${theme} mode`}</Button>
    <Input value="Hello CCM" />
    {children}
  </div>
);

export default () => (
  <Container theme="dark">
    <Container theme="light">
      <Container theme="dark">
        <Container theme="light" />
      </Container>
    </Container>
  </Container>
);
